logic [3:0][7:0] buf;
assign buf[3] = 8'hAA;
always_ff @(posedge clk) begin
  buf[0] <= 8'hBB;
  buf[1] <= buf[0];
end

typedef struct packed {
  logic       flag;
  logic [7:0] data;
} pkt_t;

pkt_t st;
assign st.flag = 1'b1;
always_ff @(posedge clk) begin
  st.data <= 8'h00;
end
